  bool FileHandle::openReadWrite (char const * filename, bool const createIfMissing)
                                                                                    {
		close();

		// Try opening existing file first.
		mFile = fopen(filename, "rb+");
		if (!mFile && createIfMissing)
			mFile = fopen(filename, "wb+");
			
		if (!mFile)
			return false;
		mMode = OM_READ_WRITE;
		return true;
		}
