namespace sttSav
{
  template <typename NODE, typename UNPACKED_KEY>
  void DictionaryLookup <NODE, UNPACKED_KEY>::reserveIds (uint32_t const numIds)
                                               {
		if (numIds <= mLookup.size()) return;
		uint32_t start = mLookup.size();
		mLookup.resize(numIds);
		for (uint32_t i = start; i < numIds; ++i) {
			mLookup[i].aid.value = i + 1;
			mLookup[i].ptr = NULL;
			}
		}
}
