  uint32_t ArchiveFile::findPendingRecord (recordId const id, bool const isForward) const
                                                                                         {
		if (isForward) {
			for (uint32_t i = 0; i < pendingRecords.size(); ++i) {
				if (pendingRecords[i].record.value == id.value)
					return i;
				}
			}
		else {
			for (uint32_t i = pendingRecords.size()-1; i < pendingRecords.size(); --i) {
				if (pendingRecords[i].record.value == id.value)
					return i;
				}
			}
		return -1;
		}
