namespace sttSav
{
  bool ArchiveFile::readRecord (recordId const id, STTSAV_STRING & recordOut)
                                                                     {
		STTSAV_ASSERT(hasLoadedRecords);
		recordOut.clear();
		
		//if (id.value == 1136) // canary testing
		//	printf("READ RECORD 1136\n");

		// Check pending changes first (newest first).
		uint32_t p = findPendingRecord(id, false);
		if (p < pendingRecords.size()) {
			const recordInfo& r = pendingRecords[p];
			// Tombstone? => Record no longer exists
			if (r.length == 0)
				return true;
			STTSAV_ASSERT(r.offset + r.length <= writeBuffer.size());
			recordOut.assign(writeBuffer.data() + r.offset, r.length);
			return true;
			}

		// Check committed records.
		uint32_t idx = findRecord(id);
		if (idx >= records.size())
			return true;	// Record does not exist.

		const recordInfo& r = records[idx];
		
		// Lazily open the archive.
		if (!file.isOpen()) {
			if (!file.openRead(filename.c_str()))
				return false;
			}
		if (!file.seek(r.offset))
			return false;

		recordOut.resize(r.length);
		if (r.length) {
			if (!file.read(recordOut.data(), r.length))
				return false;
			}
		return true;
		}
}
