namespace sttSav
{
  void ArchiveManager::loadAllRecordInfo ()
                                 {
		for (ArchiveFile* a : mArchives) {
			if (!a)
				continue;
			if (a->hasLoadedRecords)
				continue;
			a->loadRecords();
			touchedArchives.push_back(a->aid);
			}
		if (!keepFilesOpen)
			closeOpenFiles();
		}
}
namespace sttSav
{
  void ArchiveManager::unloadAllRecordInfo ()
                                   {
		for (ArchiveFile* a : mArchives) {
			if (!a) continue;
			a->unloadRecordInfo();
			}
		}
}
namespace sttSav
{
  void ArchiveManager::clearArchives ()
                             {
		closeOpenFiles();
		for (ArchiveFile* a : mArchives) {
			if (!a)
				continue;
			if (a->file.isOpen())
				a->file.close();
			STTSAV_DEL(a, sizeof(ArchiveFile));
			}
		mArchives.clear();
		}
}
namespace sttSav
{
  ArchiveFile * ArchiveManager::getOrCreate (archiveId const aid)
                                                      {
		// creates a logical archiveFile (not a physical file)
		STTSAV_ASSERT(aid.value);

		if (aid.value > mArchives.size())
			mArchives.resize(aid.value, NULL);

		mArchives[aid.value - 1] = STTSAV_NEW(ArchiveFile);

		ArchiveFile* a = mArchives[aid.value - 1];
		a->aid = aid;
		char filename[512];
		uint32_t len = 0;
		mDictionary->getArchiveFilename(aid, filename, len, sizeof(filename));

		a->filename = FileOps::joinPath(mBasePath, filename);
		a->filename.shrink_to_fit();
		a->fileExists = FileOps::exists(a->filename.c_str());
		return a;
		}
}
namespace sttSav
{
  ArchiveFile * ArchiveManager::getLazy (archiveId const aid)
                                                  {
		if (aid.value == 0) return NULL;
		if (aid.value > mArchives.size())
			return NULL;
		return mArchives[aid.value - 1];
		}
}
namespace sttSav
{
  void ArchiveManager::initArchiveFilesFromDictionary ()
                                              {
		// Delete any existing ArchiveFile handles
		clearArchives();

		// Fetch all archive ids.
		const uint32_t bufferSz = mDictionary->getArchiveCountUpperBound();

		tmpArr<archiveId, 512>ids_buff(bufferSz);
		archiveId* ids = ids_buff.getBuffer();
		uint32_t numArchives = 0;
		mDictionary->extractArchiveIds(ids, numArchives, bufferSz);

		// Allocate sparse lookup.
		mArchives.resize(numArchives, NULL);
		
		for (uint32_t i = 0; i < numArchives; ++i) {
			getOrCreate(ids[i]);
			}
		}
}
namespace sttSav
{
  void ArchiveManager::applyArchiveDelta (archiveId const * oldIds, uint32_t const numOld, archiveId const * newIds, uint32_t const numNew)
                                                                                                                               {
		// What we do is we have a list of destinations. We write all the records from the oldIds to the destArchives,
		// then destructively merge the destArchives into mArchives 
		struct DestinationArchive {
			archiveId aid;
			ArchiveFile* archive;
			bool isSameAsASource; // true => there is an identical source file to this destination file
			};
		STTSAV_VECTOR<DestinationArchive> destArchives;
		STTSAV_VECTOR<ArchiveFile*> deletionList;

		// Phase 1 - Ensure all source archives are realised.
		for (uint32_t i = 0; i < numOld; ++i) {
			const archiveId aid = oldIds[i];
			if (!aid.value || aid.value > mArchives.size())
				continue;
			ArchiveFile* src = mArchives[aid.value - 1];
			if (!src)
				continue;
			if (!src->hasLoadedRecords) {
				if (!src->loadRecords())
					STTSAV_ASSERT(false);
				}
			}

		// Phase 2 - Create destination archives.
		//
		// Surviving archives are written to "<name>.tmp".
		// Newly created archives are written directly to their final filename.
		for (uint32_t i = 0; i < numNew; ++i) {
			const archiveId aid = newIds[i];

			bool isSameAsASource = false;
			
			char filename[512];
			uint32_t len = 0;
			mDictionary->getArchiveFilename(aid, filename, len, sizeof(filename));
			STTSAV_STRING newFilename = FileOps::joinPath(mBasePath, filename);
				
			for (uint32_t j = 0; j < numOld; ++j) {
				if (oldIds[j].value == aid.value) {
					// Matching ids. Check the filenames to see if the physical file survives
					// (file names may be different after 					
					ArchiveFile* oldArchive = getLazy(aid);
					if (oldArchive) {
						#ifdef STTSAV_DBG  
						//printf("test does archive %i survive: %s -> %s (%d)\n", (int)aid.value, newFilename.c_str(), oldArchive->filename.c_str(), (oldArchive->filename == newFilename));
						#endif
						isSameAsASource = (oldArchive->filename == newFilename);
						if (!isSameAsASource)
							push_back_vector_unique(deletionList, oldArchive);
						}
					break;
					}
				}

			ArchiveFile* dst = STTSAV_NEW(ArchiveFile);

			dst->aid = aid;
			dst->filename = newFilename;
			dst->filename.shrink_to_fit();

			if (isSameAsASource)
				dst->filename += ".tmp";

			dst->fileExists = false;

			DestinationArchive da;
			da.aid = aid;
			da.archive = dst;
			da.isSameAsASource = isSameAsASource;

			destArchives.push_back(da);
			}
		// source files that do not map onto any destination files are marked for deletion
		for (uint32_t i = 0; i < numOld; ++i) {
			const archiveId aid = oldIds[i];

			bool survives = false;
			for (uint32_t j = 0; j < numNew; ++j) {
				if (newIds[j].value == aid.value) {
					survives = true;
					break;
					}
				}
			if (!survives)
			push_back_vector_unique(deletionList, getLazy(aid));
			}
			
		for (uint32_t i = 0; i < numOld; ++i) {
			const archiveId aid = oldIds[i];
			if (!aid.value || aid.value > mArchives.size())
				continue;
			ArchiveFile* src = mArchives[aid.value - 1];
			src->prepareFileForReading();
			}

		// =========================================================================
		// Phase 3 - Remap records.
		//
		// For each source archive:
		//
		//   - Iterate committed records.
		//   - Iterate pending records.
		//   - Pending writes override committed records.
		//   - Tombstones suppress committed records.
		//   - Route every surviving record into one of destArchives.
		//
		// Destination selection should use:
		//
		//     mDictionary->getArchiveIdFromShortlist(...)
		//
		// Every record must end up in exactly one destination archive.
		// =========================================================================
		
		// Build a temporary splitResult array for fast dictionary lookups.
		tmpArr<splitResult, 32> storage(numNew);
		splitResult* shortlist = storage.getBuffer();
		
		for (uint32_t i = 0; i < numNew; ++i)
			shortlist[i].aid = destArchives[i].aid;
	
		// Phase 3 - Migrate records.
		for (uint32_t oldIdx = 0; oldIdx < numOld; ++oldIdx) {
			const archiveId srcAid = oldIds[oldIdx];
			if (!srcAid.value || srcAid.value > mArchives.size())
				continue;
			ArchiveFile* src = mArchives[srcAid.value - 1];
			if (!src)
				continue;
			STTSAV_ASSERT(src->hasLoadedRecords);

			// Build dead-record table lazily.
			STTSAV_VECTOR<bool> dead;

			auto isDead = [&](const uint32_t recordIdx) -> bool {
				if (dead.empty()) {
					if (src->pendingRecords.empty())
						return false;
						
					dead.resize(src->records.size(), false);
					for (const recordInfo& p : src->pendingRecords) {
						uint32_t idx = src->findRecord(p.record);
						if (idx < src->records.size())
							dead[idx] = true;
						}
					}
				return dead[recordIdx];
				};

			// Pass 1 - committed records.
			for (uint32_t i = 0; i < src->records.size(); ++i) {
				if (isDead(i))
					continue;

				const recordInfo& r = src->records[i];
				ArchiveFile* dst = NULL;
				
				archiveId dstAid = mDictionary->getArchiveIdFromShortlist( r.key, shortlist, numNew );
				for (DestinationArchive& d : destArchives) {
					if (d.aid == dstAid) {
						dst = d.archive;
						break;
						}
					}

				STTSAV_ASSERT(dst);
				
				STTSAV_STRING buff;
				src->readRecord(r.record, buff);
				dst->prepareFileForWriting();
				dst->writeRecord(r.key, r.record, buffer(buff.data(), buff.size()));
				}

			// Pass 2 - pending records.
			for (uint32_t i = 0; i < src->pendingRecords.size(); ++i) {
				const recordInfo& r = src->pendingRecords[i];

				// Is this pending write superseded by a later operation?
				bool survives = (r.length != 0);

				if (survives) {
					for (uint32_t j = i + 1; j < src->pendingRecords.size(); ++j) {
						if (src->pendingRecords[j].record.value != r.record.value)
							continue;
						survives = (src->pendingRecords[j].length != 0);
						}
					}

				if (!survives)
					continue;

				ArchiveFile* dst = NULL;
				archiveId dstAid = mDictionary->getArchiveIdFromShortlist( r.key, shortlist, numNew );
				for (DestinationArchive& d : destArchives) {
					if (d.aid == dstAid) {
						dst = d.archive;
						break;
						}
					}

				STTSAV_ASSERT(dst);
				dst->writeRecord(r.key, r.record, buffer(src->writeBuffer.data() + r.offset, r.length));
				}
			}

		// Phase 4 - Commit destination archives.
		for (DestinationArchive& d : destArchives) {
			if (!d.archive->commit())
				STTSAV_ASSERT(false);
			}
		for (DestinationArchive& d : destArchives) {
			if (d.archive->file.isOpen())
				d.archive->file.flush();
			}
		for (DestinationArchive& d : destArchives) {
			if (d.archive->file.isOpen())
				d.archive->file.close();
			
			// We have completed compaction, so there are no wasted bytes
			d.archive->wastedBytes = 0;
			}

		// Phase 5 - Replace surviving archives.
		for (DestinationArchive& d : destArchives) {
			if (!d.isSameAsASource)
				continue;

			STTSAV_STRING finalName = d.archive->filename;
			finalName.resize(finalName.size() - 4); // remove ".tmp"

			if (!FileOps::replace( d.archive->filename.c_str(), finalName.c_str()))
				STTSAV_ASSERT(false);

			d.archive->filename = finalName;
			}
		
		// Commit the dicitonary
		if (deletionList.size() || (numOld != 1) || (numNew != 1))
			saveDictionary();

		// Phase 6 - Remove obsolete source archives.
		for (ArchiveFile* src : deletionList) {
			if (!src)
				continue;
				
			if (src->file.isOpen())
				src->file.close();
				
			#ifdef STTSAV_DBG
			//printf("DELETE %s\n", src->filename.c_str());
			#endif

			FileOps::deleteFile(src->filename.c_str());

			STTSAV_DEL(src, sizeof(ArchiveFile));
			mArchives[src->aid.value - 1] = NULL;
			}

		// Phase 7 - merge our mArchive vectors
		for (DestinationArchive& d : destArchives) {
			if (d.aid.value > mArchives.size())
				mArchives.resize(d.aid.value, NULL);

			if (mArchives[d.aid.value - 1])
				STTSAV_DEL(mArchives[d.aid.value - 1], sizeof(ArchiveFile));
				
			mArchives[d.aid.value - 1] = d.archive;
			}
		}
}
